    isHistoryOpen: false,
  },
};

export const EmptyState: Story = {
  args: {
    chats: [],
    activeChatId: null,
  },
};

export const WithError: Story = {
  args: {
    error: 'Не удалось отправить вопрос',
    draft: 'Повторить запрос',
  },
};

import { Menu as MenuIcon } from '@mui/icons-material';
import { Alert, Box, IconButton, Paper, Typography } from '@mui/material';

import { ChatComposer } from './ChatComposer';
import { ChatHistoryPanel } from './ChatHistoryPanel';
import { ChatThreadView } from './ChatThreadView';
import { DEFAULT_LABELS } from './labels';
import type { AiAssistantProps } from './types';

export function AiAssistant(props: AiAssistantProps) {
  const {
    chats,
    activeChatId,
    isHistoryOpen,
    draft,
    isSubmitting,
    error,
    labels,
    onDraftChange,
    onSendQuestion,
    onStartNewChat,
    onDeleteChat,
    onToggleHistory,
    onSelectChat,
  } = props;

  const uiLabels = { ...DEFAULT_LABELS, ...(labels ?? {}) };
  const activeChat = chats.find((chat) => chat.id === activeChatId);

  const submitDisabled = isSubmitting || draft.trim().length === 0 || activeChatId === null;

  return (
    <Paper sx={{ height: '100%', minHeight: 560, display: 'flex', overflow: 'hidden' }}>
      {isHistoryOpen ? (
        <ChatHistoryPanel
          chats={chats}
          activeChatId={activeChatId}
          noChatsLabel={uiLabels.noChats}
          onStartNewChat={onStartNewChat}
          onDeleteChat={onDeleteChat}
          onSelectChat={onSelectChat}
          newChatLabel={uiLabels.newChat}
          deleteChatLabel={uiLabels.deleteChat}
          historyLabel={uiLabels.history}
        />
      ) : null}

      <Box sx={{ flex: 1, display: 'flex', flexDirection: 'column', minWidth: 0 }}>
        <Box
          sx={{
            p: 1.5,
            borderBottom: 1,
            borderColor: 'divider',
            display: 'flex',
            alignItems: 'center',
            gap: 1,
          }}
        >
          <IconButton size="small" onClick={onToggleHistory} aria-label={uiLabels.history}>
            <MenuIcon fontSize="small" />
          </IconButton>
          <Typography variant="subtitle1" sx={{ fontWeight: 700 }}>
            {uiLabels.title}
          </Typography>
        </Box>

        {error ? (
          <Box sx={{ p: 2, pb: 0 }}>
            <Alert severity="error">{error}</Alert>
          </Box>
        ) : null}

        <Box sx={{ flex: 1, overflowY: 'auto' }}>
          <ChatThreadView activeChat={activeChat} noMessagesLabel={uiLabels.noMessages} />
        </Box>

        <ChatComposer
          value={draft}
          placeholder={uiLabels.askPlaceholder}
          sendLabel={uiLabels.send}
          disabled={submitDisabled}
          onChange={onDraftChange}
          onSubmit={() => onSendQuestion(draft)}
        />
      </Box>
    </Paper>
  );
}

import { Box, Button, TextField } from '@mui/material';

interface ChatComposerProps {
  value: string;
  placeholder: string;
  sendLabel: string;
  disabled: boolean;
  onChange: (value: string) => void;
  onSubmit: () => void;
}

export function ChatComposer(props: ChatComposerProps) {
  const { value, placeholder, sendLabel, disabled, onChange, onSubmit } = props;

  return (
    <Box sx={{ p: 2, borderTop: 1, borderColor: 'divider', display: 'flex', gap: 1 }}>
      <TextField
        fullWidth
        size="small"
        placeholder={placeholder}
        value={value}
        onChange={(event) => onChange(event.target.value)}
        onKeyDown={(event) => {
          if (event.key === 'Enter' && !event.shiftKey) {
            event.preventDefault();
            if (!disabled) {
              onSubmit();
            }
          }
        }}
      />
      <Button variant="contained" disabled={disabled} onClick={onSubmit}>
        {sendLabel}
      </Button>
    </Box>
  );
}

import { DeleteOutline as DeleteOutlineIcon } from '@mui/icons-material';
import { Box, Button, Divider, IconButton, List, ListItemButton, ListItemText, Typography } from '@mui/material';

import type { ChatSession } from './types';

interface ChatHistoryPanelProps {
  chats: ChatSession[];
  activeChatId: string | null;
  noChatsLabel: string;
  onStartNewChat: () => void;
  onDeleteChat: (chatId: string) => void;
  onSelectChat: (chatId: string) => void;
  newChatLabel: string;
  deleteChatLabel: string;
  historyLabel: string;
}

export function ChatHistoryPanel(props: ChatHistoryPanelProps) {
  const {
    chats,
    activeChatId,
    noChatsLabel,
    onStartNewChat,
    onDeleteChat,
    onSelectChat,
    newChatLabel,
    deleteChatLabel,
    historyLabel,
  } = props;

  return (
    <Box sx={{ width: 280, borderRight: 1, borderColor: 'divider', display: 'flex', flexDirection: 'column' }}>
      <Box sx={{ p: 2, display: 'flex', flexDirection: 'column', gap: 1 }}>
        <Typography variant="subtitle2" sx={{ fontWeight: 700 }}>
          {historyLabel}
        </Typography>
        <Button variant="contained" onClick={onStartNewChat}>
          {newChatLabel}
        </Button>
      </Box>
      <Divider />
      <List sx={{ overflowY: 'auto', flex: 1 }}>
        {chats.length === 0 ? (
          <Box sx={{ p: 2 }}>
            <Typography variant="body2" color="text.secondary">
              {noChatsLabel}
            </Typography>
          </Box>
        ) : (
          chats.map((chat) => (
            <ListItemButton
              key={chat.id}
              selected={chat.id === activeChatId}
              onClick={() => onSelectChat(chat.id)}
            >
              <ListItemText
                primary={chat.title}
                secondary={new Date(chat.updatedAt).toLocaleString()}
                primaryTypographyProps={{ noWrap: true }}
              />
              <IconButton
                size="small"
                edge="end"
                aria-label={`${deleteChatLabel}: ${chat.title}`}
                onClick={(event) => {
                  event.stopPropagation();
                  onDeleteChat(chat.id);
                }}
              >
                <DeleteOutlineIcon fontSize="small" />
              </IconButton>
            </ListItemButton>
          ))
        )}
      </List>
    </Box>
  );
}

import { Box, Paper, Typography } from '@mui/material';

import type { ChatSession } from './types';

interface ChatThreadViewProps {
  activeChat: ChatSession | undefined;
  noMessagesLabel: string;
}

export function ChatThreadView({ activeChat, noMessagesLabel }: ChatThreadViewProps) {
  const messages = activeChat?.messages ?? [];

  if (messages.length === 0) {
    return (
      <Box sx={{ p: 3 }}>
        <Typography variant="body2" color="text.secondary">
          {noMessagesLabel}
        </Typography>
      </Box>
    );
  }

  return (
    <Box sx={{ p: 2, display: 'flex', flexDirection: 'column', gap: 1.5 }}>
      {messages.map((message) => {
        const isUser = message.role === 'user';

        return (
          <Paper
            key={message.id}
            variant="outlined"
            sx={{
              p: 1.5,
              alignSelf: isUser ? 'flex-end' : 'flex-start',
              maxWidth: '80%',
              bgcolor: isUser ? 'primary.main' : 'background.paper',
              color: isUser ? 'primary.contrastText' : 'text.primary',
              borderRadius: 2,
            }}
          >
            <Typography variant="body2">{message.text}</Typography>
          </Paper>
        );
      })}
    </Box>
  );
}

export { AiAssistant } from './AiAssistant';
export { chatReducer, createInitialChatState, createNewChat, createUserMessage } from './reducer/chatReducer';
export type { ChatAction, ChatState } from './reducer/chatReducer';
export type {
  AiAssistantProps,
  AiAssistantLabels,
  ChatSession,
  ChatMessage,
  MessageAttachment,
  MessageRole,
  MessageStatus,
} from './types';

import type { AiAssistantLabels } from './types';

export const DEFAULT_LABELS: AiAssistantLabels = {
  title: 'AI Ассистент',
  newChat: 'Новый чат',
  deleteChat: 'Удалить чат',
  history: 'История чатов',
  askPlaceholder: 'Введите вопрос...',
  send: 'Отправить',
  noChats: 'Чатов пока нет',
  noMessages: 'Начните диалог с ассистентом',
};

import {
  chatReducer,
  createInitialChatState,
  createNewChat,
  createUserMessage,
  type ChatState,
} from './chatReducer';

describe('chatReducer', () => {
  it('starts a new chat and sets it active', () => {
    const start = createInitialChatState();
    const chat = createNewChat('chat-1', '2026-04-26T10:00:00.000Z');

    const next = chatReducer(start, { type: 'START_NEW_CHAT', payload: { chat } });

    expect(next.chats).toHaveLength(1);
    expect(next.activeChatId).toBe('chat-1');
    expect(next.chats[0]?.title).toBe('Новый чат');
  });

  it('toggles history visibility', () => {
    const start = createInitialChatState();

    const next = chatReducer(start, { type: 'TOGGLE_HISTORY' });

    expect(next.isHistoryOpen).toBe(false);
  });

  it('appends user message to active chat and clears draft', () => {
    const chat = createNewChat('chat-1', '2026-04-26T10:00:00.000Z');
    const start: ChatState = {
      chats: [chat],
      activeChatId: 'chat-1',
      isHistoryOpen: true,
      draft: 'Как заполнить шаблон?',
      isSubmitting: false,
      error: null,
    };

    const message = createUserMessage({
      id: 'msg-1',
      text: 'Как заполнить шаблон?',
      createdAt: '2026-04-26T10:00:01.000Z',
    });

    const next = chatReducer(start, { type: 'SEND_QUESTION', payload: { message } });

    expect(next.chats[0]?.messages).toHaveLength(1);
    expect(next.chats[0]?.messages[0]?.text).toBe('Как заполнить шаблон?');
    expect(next.draft).toBe('');
    expect(next.error).toBeNull();
  });

  it('sets active chat from history', () => {
    const first = createNewChat('chat-1', '2026-04-26T10:00:00.000Z');
    const second = createNewChat('chat-2', '2026-04-26T10:01:00.000Z');
    const start: ChatState = {
      chats: [first, second],
      activeChatId: 'chat-1',
      isHistoryOpen: true,
      draft: '',
      isSubmitting: false,
      error: null,
    };

    const next = chatReducer(start, { type: 'SELECT_CHAT', payload: { chatId: 'chat-2' } });

    expect(next.activeChatId).toBe('chat-2');
  });
});

import {
  chatReducer,
  createInitialChatState,
  createNewChat,
  createUserMessage,
  type ChatState,
} from './chatReducer';

describe('chatReducer', () => {
  it('starts a new chat and sets it active', () => {
    const start = createInitialChatState();
    const chat = createNewChat('chat-1', '2026-04-26T10:00:00.000Z');

    const next = chatReducer(start, { type: 'START_NEW_CHAT', payload: { chat } });

    expect(next.chats).toHaveLength(1);
    expect(next.activeChatId).toBe('chat-1');
    expect(next.chats[0]?.title).toBe('Новый чат');
  });

  it('toggles history visibility', () => {
    const start = createInitialChatState();

    const next = chatReducer(start, { type: 'TOGGLE_HISTORY' });

    expect(next.isHistoryOpen).toBe(false);
  });

  it('appends user message to active chat and clears draft', () => {
    const chat = createNewChat('chat-1', '2026-04-26T10:00:00.000Z');
    const start: ChatState = {
      chats: [chat],
      activeChatId: 'chat-1',
      isHistoryOpen: true,
      draft: 'Как заполнить шаблон?',
      isSubmitting: false,
      error: null,
    };

    const message = createUserMessage({
      id: 'msg-1',
      text: 'Как заполнить шаблон?',
      createdAt: '2026-04-26T10:00:01.000Z',
    });

    const next = chatReducer(start, { type: 'SEND_QUESTION', payload: { message } });

    expect(next.chats[0]?.messages).toHaveLength(1);
    expect(next.chats[0]?.messages[0]?.text).toBe('Как заполнить шаблон?');
    expect(next.draft).toBe('');
    expect(next.error).toBeNull();
  });

  it('sets active chat from history', () => {
    const first = createNewChat('chat-1', '2026-04-26T10:00:00.000Z');
    const second = createNewChat('chat-2', '2026-04-26T10:01:00.000Z');
    const start: ChatState = {
      chats: [first, second],
      activeChatId: 'chat-1',
      isHistoryOpen: true,
      draft: '',
      isSubmitting: false,
      error: null,
    };

    const next = chatReducer(start, { type: 'SELECT_CHAT', payload: { chatId: 'chat-2' } });

    expect(next.activeChatId).toBe('chat-2');
  });

  it('deletes non-active chat and keeps current active chat', () => {
    const first = createNewChat('chat-1', '2026-04-26T10:00:00.000Z');
    const second = createNewChat('chat-2', '2026-04-26T10:01:00.000Z');
    const start: ChatState = {
      chats: [first, second],
      activeChatId: 'chat-1',
      isHistoryOpen: true,
      draft: '',
      isSubmitting: false,
      error: null,
    };

    const next = chatReducer(start, { type: 'DELETE_CHAT', payload: { chatId: 'chat-2' } });

    expect(next.chats).toHaveLength(1);
    expect(next.chats[0]?.id).toBe('chat-1');
    expect(next.activeChatId).toBe('chat-1');
  });

  it('deletes active chat and switches active chat to first remaining one', () => {
    const first = createNewChat('chat-1', '2026-04-26T10:00:00.000Z');
    const second = createNewChat('chat-2', '2026-04-26T10:01:00.000Z');
    const start: ChatState = {
      chats: [first, second],
      activeChatId: 'chat-1',
      isHistoryOpen: true,
      draft: '',
      isSubmitting: false,
      error: null,
    };

    const next = chatReducer(start, { type: 'DELETE_CHAT', payload: { chatId: 'chat-1' } });

    expect(next.chats).toHaveLength(1);
    expect(next.chats[0]?.id).toBe('chat-2');
    expect(next.activeChatId).toBe('chat-2');
  });

  it('deletes the last chat and resets activeChatId to null', () => {
    const only = createNewChat('chat-1', '2026-04-26T10:00:00.000Z');
    const start: ChatState = {
      chats: [only],
      activeChatId: 'chat-1',
      isHistoryOpen: true,
      draft: '',
      isSubmitting: false,
      error: null,
    };

    const next = chatReducer(start, { type: 'DELETE_CHAT', payload: { chatId: 'chat-1' } });

    expect(next.chats).toHaveLength(0);
    expect(next.activeChatId).toBeNull();
  });
});

import type { ChatMessage, ChatSession } from '../types';

export interface ChatState {
  chats: ChatSession[];
  activeChatId: string | null;
  isHistoryOpen: boolean;
  draft: string;
  isSubmitting: boolean;
  error: string | null;
}

export type ChatAction =
  | { type: 'SET_DRAFT'; payload: { draft: string } }
  | { type: 'START_NEW_CHAT'; payload: { chat: ChatSession } }
  | { type: 'SELECT_CHAT'; payload: { chatId: string } }
  | { type: 'DELETE_CHAT'; payload: { chatId: string } }
  | { type: 'TOGGLE_HISTORY' }
  | { type: 'SEND_QUESTION'; payload: { message: ChatMessage } }
  | { type: 'SET_SUBMITTING'; payload: { value: boolean } }
  | { type: 'SET_ERROR'; payload: { error: string | null } }
  | { type: 'RECEIVE_ASSISTANT_MESSAGE'; payload: { chatId: string; message: ChatMessage } };

export function createInitialChatState(): ChatState {
  return {
    chats: [],
    activeChatId: null,
    isHistoryOpen: true,
    draft: '',
    isSubmitting: false,
    error: null,
  };
}

export function createNewChat(chatId: string, nowIso: string): ChatSession {
  return {
    id: chatId,
    title: 'Новый чат',
    createdAt: nowIso,
    updatedAt: nowIso,
    messages: [],
  };
}

export function createUserMessage(input: {
  id: string;
  text: string;
  createdAt: string;
}): ChatMessage {
  return {
    id: input.id,
    role: 'user',
    text: input.text,
    createdAt: input.createdAt,
    status: 'sent',
    kind: 'text',
  };
}

export function chatReducer(state: ChatState, action: ChatAction): ChatState {
  switch (action.type) {
    case 'SET_DRAFT':
      return { ...state, draft: action.payload.draft };

    case 'START_NEW_CHAT':
      return {
        ...state,
        chats: [action.payload.chat, ...state.chats],
        activeChatId: action.payload.chat.id,
        error: null,
      };

    case 'SELECT_CHAT':
      return { ...state, activeChatId: action.payload.chatId };

    case 'DELETE_CHAT': {
      const chats = state.chats.filter((chat) => chat.id !== action.payload.chatId);
      const activeChatId =
        state.activeChatId === action.payload.chatId ? (chats[0]?.id ?? null) : state.activeChatId;

      return {
        ...state,
        chats,
        activeChatId,
      };
    }

    case 'TOGGLE_HISTORY':
      return { ...state, isHistoryOpen: !state.isHistoryOpen };

    case 'SET_SUBMITTING':
      return { ...state, isSubmitting: action.payload.value };

    case 'SET_ERROR':
      return { ...state, error: action.payload.error };

    case 'SEND_QUESTION': {
      if (!state.activeChatId) {
        return state;
      }

      const chats = state.chats.map((chat) => {
        if (chat.id !== state.activeChatId) {
          return chat;
        }

        return {
          ...chat,
          updatedAt: action.payload.message.createdAt,
          title: resolveChatTitle(chat.title, action.payload.message.text),
          messages: [...chat.messages, action.payload.message],
        };
      });

      return {
        ...state,
        chats,
        draft: '',
        error: null,
      };
    }

    case 'RECEIVE_ASSISTANT_MESSAGE': {
      const chats = state.chats.map((chat) => {
        if (chat.id !== action.payload.chatId) {
          return chat;
        }

        return {
          ...chat,
          updatedAt: action.payload.message.createdAt,
          messages: [...chat.messages, action.payload.message],
        };
      });

      return { ...state, chats };
    }

    default:
      return state;
  }
}

function resolveChatTitle(currentTitle: string, question: string): string {
  if (currentTitle !== 'Новый чат') {
    return currentTitle;
  }

  const trimmed = question.trim();
  if (!trimmed) {
    return currentTitle;
  }

  const max = 32;
  return trimmed.length <= max ? trimmed : `${trimmed.slice(0, max)}...`;
}

export type MessageRole = 'user' | 'assistant' | 'system';

export type MessageStatus = 'pending' | 'sent' | 'error' | 'streaming';

export interface MessageAttachment {
  id: string;
  name: string;
  mimeType: string;
  size: number;
  url?: string;
  previewUrl?: string;
  meta?: Record<string, unknown>;
}

export interface ChatMessage {
  id: string;
  role: MessageRole;
  text: string;
  createdAt: string;
  status: MessageStatus;
  kind: string;
  meta?: Record<string, unknown>;
  attachments?: MessageAttachment[];
}

export interface ChatSession {
  id: string;
  title: string;
  createdAt: string;
  updatedAt: string;
  messages: ChatMessage[];
  meta?: Record<string, unknown>;
}

export interface AiAssistantLabels {
  title: string;
  newChat: string;
  deleteChat: string;
  history: string;
  askPlaceholder: string;
  send: string;
  noChats: string;
  noMessages: string;
}

export interface AiAssistantProps {
  chats: ChatSession[];
  activeChatId: string | null;
  isHistoryOpen: boolean;
  draft: string;
  isSubmitting: boolean;
  error?: string | null;
  labels?: Partial<AiAssistantLabels>;
  onDraftChange: (value: string) => void;
  onSendQuestion: (question: string) => void;
  onStartNewChat: () => void;
  onDeleteChat: (chatId: string) => void;
  onToggleHistory: () => void;
  onSelectChat: (chatId: string) => void;
}
